import React from 'react';
import { Button, StatusBadge } from '@linm-soft-org/linm-web-common-components';
import legacyStyles from '../legacy/legacyField.module.css';
import df from '../../styles/documentForm.module.css';

export interface DocumentFormHeaderProps {
  onBack: () => void;
  title: string;
  /** Số chứng từ cũ (legacyId) — read-only row under title when migrate. */
  legacyId?: string | null;
  legacyIdLabel?: string;
  status?: string;
  isReadOnly?: boolean;
  saving?: boolean;
  isNew?: boolean;
  saveLabel?: string;
  saveEditLabel?: string;
  onSave?: () => void;
  onDelete?: () => void;
  showDelete?: boolean;
  deleting?: boolean;
  extraActions?: React.ReactNode;
}

export const DocumentFormHeader: React.FC<DocumentFormHeaderProps> = ({
  onBack,
  title,
  legacyId,
  legacyIdLabel = 'Số chứng từ cũ',
  status,
  isReadOnly,
  saving,
  isNew,
  saveLabel = 'Lưu',
  saveEditLabel = 'Lưu thay đổi',
  onSave,
  onDelete,
  showDelete,
  deleting,
  extraActions,
}) => (
  <div className={df.stickyTop}>
    <div className={df.pageHeader}>
      <div className={df.titleGroup}>
        <button type="button" className={df.backBtn} onClick={onBack}>
          ← Quay lại
        </button>
        <div>
          <div className={df.titleRow}>
            <h1 className={df.title}>{title}</h1>
            {status && !isNew && <StatusBadge status={status} />}
          </div>
          {legacyId?.trim() ? (
            <div className={legacyStyles.legacyIdRow} data-testid="form-legacy-id">
              <span className={legacyStyles.legacyIdLabel}>{legacyIdLabel}</span>
              <span className={legacyStyles.legacyIdValue}>{legacyId.trim()}</span>
            </div>
          ) : null}
          {isReadOnly && (
            <div className={df.readOnlyHint}>🔒 Chỉ xem — không thể chỉnh sửa</div>
          )}
        </div>
      </div>
      <div className={df.headerActions}>
        {extraActions}
        {!isReadOnly && onSave && (
          <Button variant="primary" onClick={onSave} loading={saving}>
            {isNew ? saveLabel : saveEditLabel}
          </Button>
        )}
        {showDelete && onDelete && (
          <Button variant="danger" onClick={onDelete} loading={deleting}>
            Xóa
          </Button>
        )}
      </div>
    </div>
  </div>
);
