import React from 'react';
import { Button, Modal } from '@linm-soft-org/linm-web-common-components';

export interface UnsavedChangesModalProps {
  isOpen: boolean;
  onStay: () => void;
  onLeave: () => void;
  'data-testid'?: string;
}

export const UnsavedChangesModal: React.FC<UnsavedChangesModalProps> = ({
  isOpen,
  onStay,
  onLeave,
  'data-testid': testId = 'unsaved-changes-modal',
}) => (
  <Modal
    isOpen={isOpen}
    onClose={onStay}
    title="Bạn có dữ liệu chưa lưu"
    size="sm"
    closeOnOverlayClick={false}
    data-testid={testId}
  >
    <p style={{ marginBottom: '20px', color: 'var(--color-text-secondary, #6b7280)' }}>
      Tất cả thay đổi chưa được lưu sẽ bị mất. Bạn có chắc muốn rời khỏi trang này không?
    </p>
    <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
      <Button variant="secondary" onClick={onStay} data-testid={`${testId}-stay`}>
        Ở lại trang
      </Button>
      <Button variant="danger" onClick={onLeave} data-testid={`${testId}-leave`}>
        <i className="fas fa-sign-out-alt" /> Rời khỏi trang
      </Button>
    </div>
  </Modal>
);
